export const INTENSITY = ["Low", "Medium", "High", "Max"];

export const DRILLS = [
  { id: "ss1", cat: "shot-stopping", name: "Rapid Fire Triangle", dur: 15, int: "High", desc: "Three shooters stand around the box about 10-12 yards out, each at a different angle. They shoot one after another — the keeper saves one and immediately gets ready for the next. Switch shooter positions between sets.", reps: "3 sets x 10-12 shots", eq: ["Cones", "Balls", "GK Gloves"], cp: "Get back into your ready position between every save. Feet shoulder-width, weight on your toes, hands in front. If you're still moving when the ball comes, you're too slow.", prog: "Mix up shot heights; add curling shots; throw in rebounds after saves", mistakes: "Dropping hands between shots; lazy footwork; switching off mid-set", video: "https://www.youtube.com/results?search_query=goalkeeper+rapid+fire+triangle+drill" },
  { id: "ss2", cat: "shot-stopping", name: "Close-Range Volleys", dur: 12, int: "High", desc: "One server stands 6-8 yards out and fires volleys at different heights and speeds — no breaks between shots. The keeper handles everything in the air. Swap out every 15 shots.", reps: "3 sets x 15 volleys", eq: ["Balls", "GK Gloves"], cp: "Stay tight and compact. Get your hands in position early. Catch clean — no spills. Keep your feet balanced the whole time.", prog: "Faster serves; bigger height differences; change the angle; add direction changes", mistakes: "Reaching too far; feet stuck to the ground; dropping easy catches; wrong body shape for the height", video: "https://www.youtube.com/results?search_query=goalkeeper+close+range+volley+handling+drill" },
  { id: "ss3", cat: "shot-stopping", name: "Save + Rebound Pressure", dur: 15, int: "High", desc: "Someone shoots from 8 yards. Right after the keeper makes the save, an attacker runs in from the side to challenge for the loose ball. The keeper has to hold it, clear it, or make a second save.", reps: "3 sets x 10 sequences", eq: ["Balls", "Cones", "GK Gloves"], cp: "Grab the ball immediately after the first save. Decide fast: hold or throw. Get your body between the ball and the incoming attacker.", prog: "Faster attacker; add a second attacker; less time between shot and rush", mistakes: "Slow to secure the ball; fumbling under pressure; not talking; weak clearances", video: "https://www.youtube.com/results?search_query=goalkeeper+rebound+save+second+ball+drill" },
  { id: "ss4", cat: "shot-stopping", name: "Long-Range Shot Handling", dur: 15, int: "Medium", desc: "3-4 shooters line up 18-25 yards from goal at different angles. They hit hard, driven shots with time in the air. The keeper reads the flight early and gets into position.", reps: "3 sets x 12 shots", eq: ["Balls", "Cones", "GK Gloves"], cp: "Don't wander too far off your line. Pick up the flight early. Move your feet — don't just throw yourself at it. Hands at the right height before the ball arrives.", prog: "Add swerving shots; mix high and low; add deflections off a mannequin; speed up the sequence", mistakes: "Standing too far out; diving too early; losing the ball in flight; slow to move sideways", video: "https://www.youtube.com/results?search_query=goalkeeper+long+range+shot+stopping+drill" },
  { id: "ss5", cat: "shot-stopping", name: "Ready Position Drill", dur: 10, int: "Low", desc: "Keeper stands on the goal line. Coach shouts 'set' and the keeper drops into their stance. Coach checks everything: feet apart, weight forward, hands up, eyes on the ball. Reset and go again.", reps: "3 x 10 reps", eq: ["Cones", "GK Gloves"], cp: "Soft knees, lean slightly forward, hands at hip height and ready. This is the foundation of every save — get it right and everything else gets easier.", prog: "Add a shuffle between reps; speed up the calls; fire a shot right after they set", mistakes: "Weight on heels; hands down by sides; feet too close together; standing too tall", video: "https://www.youtube.com/results?search_query=goalkeeper+set+position+ready+stance+drill" },
  { id: "ss6", cat: "shot-stopping", name: "Catching Technique (W-Grip)", dur: 10, int: "Low", desc: "Coach throws balls at different heights from about 8 metres. This is only about hand shape — thumbs behind the ball for high catches, pinkies together for low ones. No pressure, just clean technique.", reps: "3 x 12 catches each", eq: ["Balls", "GK Gloves"], cp: "Make the W shape with your hands. No chicken wings. Bring the ball into your chest every time. Go to the ball — don't wait for it to come to you.", prog: "Faster throws; throw from different angles; progress to driven balls; add movement before catching", mistakes: "Fingers too close together; catching behind your head; not cushioning into the chest", video: "https://www.youtube.com/results?search_query=goalkeeper+W+catch+technique+handling+drill" },
  { id: "ss7", cat: "shot-stopping", name: "Pass Combo into Shot", dur: 15, int: "High", desc: "Two outfield players do a quick one-two pass combination and then one of them shoots from about 16 metres. The keeper has to follow the ball through the passes and be set before the shot comes.", reps: "3 x 8 combos each GK", eq: ["Balls", "Cones", "GK Gloves"], cp: "Watch the ball the whole time — adjust your position as it moves between players. Be completely still and set by the time the striker shoots.", prog: "Longer passing sequences; quicker play; add a deflector in front of goal", mistakes: "Standing still during the passes; still shuffling when the shot comes", video: "https://www.youtube.com/results?search_query=goalkeeper+combination+play+shot+stopping+drill" },
  { id: "ss8", cat: "shot-stopping", name: "Live Shooting Game", dur: 15, int: "Max", desc: "Three players take turns shooting from the edge of the box at full match speed. No soft shots. Keeper rotates out every 6 shots. Treat it like a real game — compete.", reps: "4 rounds x 6 shots each GK", eq: ["Balls", "Cones", "GK Gloves"], cp: "This is a competition, not a drill. Celebrate your saves. Check your position after every shot. Match-day mentality.", prog: "More shooters; add passing combinations before the shot; put a time limit on each round", mistakes: "Going through the motions; not resetting between shots; looking defeated after a goal", video: "https://www.youtube.com/results?search_query=goalkeeper+live+shooting+match+intensity+drill" },
  { id: "ss9", cat: "shot-stopping", name: "Edge of Box Driven Shots", dur: 15, int: "High", desc: "Three shooters take turns firing from different spots along the edge of the 18-yard box at full power. No gentle deliveries. Keeper swaps after every 8 shots.", reps: "4 x 8 shots per GK", eq: ["Balls", "Cones", "GK Gloves"], cp: "Be set before the shot. Explode towards the corner. Read the shooter's hips and body shape to know where it's going.", prog: "Add a pass combination before the shot; mix up shot types; add a second ball straight after", mistakes: "Bad starting position; diving before the shot is hit; not reading the shooter's body", video: "https://www.youtube.com/results?search_query=goalkeeper+edge+of+box+shot+stopping+drill" },
  { id: "ss10", cat: "shot-stopping", name: "Screened Shot Reactions", dur: 12, int: "High", desc: "Two players stand about 5 metres in front of the keeper. A shooter fires from 20 metres — the keeper can't see the ball until it gets past the screen. Pure reaction.", reps: "4 x 8 shots", eq: ["Balls", "Cones", "GK Gloves", "Mannequins"], cp: "Line up with the shooter's hips, not the screen. Try to spot the ball at the edge of the screen. Stay on your toes — you'll have almost no time.", prog: "Add more players to the screen; change shooting angles; harder shots", mistakes: "Lining up with the screen instead of the shooter; losing focus; guessing instead of reacting", video: "https://www.youtube.com/results?search_query=goalkeeper+screened+shot+deflection+reaction+drill" },
  { id: "ss11", cat: "shot-stopping", name: "High Ball + Low Shot Combo", dur: 15, int: "High", desc: "A cross comes in high — the keeper punches or catches it. Immediately after landing, a second ball is driven low into the corner. Tests how fast you can switch from an aerial to a ground-level save.", reps: "4 x 8 sequences each GK", eq: ["Balls", "Cones", "GK Gloves"], cp: "Land on balance. Start looking for the second ball before your feet even hit the ground. The transition from aerial to shot-stop has to be instant.", prog: "Shorter gap between balls; add a third ball; change the angles", mistakes: "Landing off-balance; slow to recover from the jump; not scanning for the second ball", video: "https://www.youtube.com/results?search_query=goalkeeper+cross+then+shot+transition+drill" },
  { id: "dv1", cat: "diving", name: "Kneeling Dive Progression", dur: 10, int: "Low", desc: "Start on your knees. Coach tosses a ball to one side along the ground. You dive and get the right shape: bottom leg stretched out, bottom hand under the ball, top hand on top to lock it in. Do both sides, then stand up and repeat.", reps: "3 x 10 (5 each side)", eq: ["Balls", "GK Gloves"], cp: "Lead with your hands, not your shoulder. Watch the ball all the way in. Bottom hand goes down first, top hand secures.", prog: "Throw it further away; mix up the height; progress to standing; add a shuffle before the dive", mistakes: "Leading with the shoulder; not pinning the ball to the ground; tensing up on the way down", video: "https://www.youtube.com/results?search_query=goalkeeper+kneeling+dive+progression+drill" },
  { id: "dv2", cat: "diving", name: "Collapse Dive Technique", dur: 12, int: "Medium", desc: "From standing, take one step out at a 45-degree angle and collapse down to save a low ball. Coach rolls or throws it to your side. Focus on going down smoothly and landing in good shape.", reps: "3 x 8 each side", eq: ["Balls", "GK Gloves", "Cones"], cp: "Keep your head still as you go down. Bottom hand first, top hand over the ball. Drive into the save, don't just fall. Land on your side, not your stomach.", prog: "Faster deliveries; add footwork before the dive; throw in a recovery save after", mistakes: "Falling backwards instead of forward and across; shoulder going first instead of hands", video: "https://www.youtube.com/results?search_query=goalkeeper+collapse+dive+technique+drill" },
  { id: "dv3", cat: "diving", name: "Power Step + Extension Dive", dur: 15, int: "High", desc: "Take one explosive step at 45 degrees and then fully stretch out to reach a ball the coach throws about 1.5 metres beyond your comfortable range. Do both sides.", reps: "4 x 6 each side", eq: ["Balls", "GK Gloves"], cp: "That first step has to go at 45 degrees, not sideways. Push hard off that foot. Stretch out completely. Reach with the top hand.", prog: "Throw it further; speed up delivery; focus on one-handed tips; add a recovery save after", mistakes: "Stepping sideways; jumping up instead of driving across; hands in the wrong spot", video: "https://www.youtube.com/results?search_query=goalkeeper+extension+dive+power+step+drill" },
  { id: "dv4", cat: "diving", name: "Recovery Dive Sequence", dur: 15, int: "High", desc: "Coach serves a low ball to one side. Make the save, spring back up, and immediately dive the other way for a second ball. It's all about how fast you can get back on your feet.", reps: "3 x 10 double-dives", eq: ["Balls", "GK Gloves"], cp: "Push off the ground with your hands to get up fast. Reset properly before the second dive. Keep your technique clean even when you're tired.", prog: "Less time between balls; add a third dive; harder serves; coach moves closer", mistakes: "Slow to get up; sloppy technique on the second dive; committing too hard to the first one", video: "https://www.youtube.com/results?search_query=goalkeeper+recovery+dive+sequence+drill" },
  { id: "dv5", cat: "diving", name: "Three-Ball Sequence", dur: 12, int: "High", desc: "Coach fires three balls one after another with no pause. Ball one comes straight at you, ball two goes far left, ball three goes far right. You have to save all three.", reps: "4 x 3-ball sets each GK", eq: ["Balls", "GK Gloves"], cp: "Get up between each ball. Reset your hands every time. Treat each save like a fresh one.", prog: "Speed it up; change the order each time; add a fourth ball; more power on the serves", mistakes: "Staying on the ground; slow to get your hands ready; guessing which way it's going", video: "https://www.youtube.com/results?search_query=goalkeeper+three+ball+diving+sequence+drill" },
  { id: "dv6", cat: "diving", name: "Side-Shuffle to Dive", dur: 12, int: "Medium", desc: "Shuffle along the goal line. When the coach shouts 'freeze,' stop dead. Coach immediately throws a ball that needs a dive. The point is to go from moving to saving as fast as possible.", reps: "3 x 10 dives", eq: ["Balls", "Cones", "GK Gloves"], cp: "Keep your shuffle tight with small steps and bent knees. Stop clean and balanced. Launch into the dive right away.", prog: "Shuffle faster; freeze at different spots; harder dives; multiple dives per go", mistakes: "Slow shuffle; off-balance when you stop; delayed dive", video: "https://www.youtube.com/results?search_query=goalkeeper+shuffle+to+dive+reaction+drill" },
  { id: "dv7", cat: "diving", name: "High Extension Saves", dur: 12, int: "High", desc: "Coach throws the ball to your side at about head height, just out of comfortable reach. You push off and fully extend to get there. Both sides.", reps: "4 x 6 each side", eq: ["Balls", "GK Gloves"], cp: "Push off your inside foot. Reach with the top hand. Use both feet to jump for maximum height.", prog: "Throw it further; faster delivery; focus on one-handed tips; add recovery saves", mistakes: "Weak first step; losing control in the air; reaching too late", video: "https://www.youtube.com/results?search_query=goalkeeper+high+extension+dive+save+drill" },
  { id: "dv8", cat: "diving", name: "45-Degree Angle Focus Drill", dur: 10, int: "Low", desc: "This is a slow, technical drill. The whole focus is on getting that first step at exactly 45 degrees. Coach watches and corrects. Lots of reps, no rush.", reps: "4 x 12 dives (6 per side)", eq: ["Balls", "Cones", "GK Gloves"], cp: "First step MUST go at 45 degrees. The second step is your driving leg. Feel the weight transfer through your whole foot.", prog: "Speed it up while keeping the angle right; add more complex setups; build to game speed", mistakes: "Stepping too sideways; stepping too forward; poor weight transfer; hips pointing the wrong way", video: "https://www.youtube.com/results?search_query=goalkeeper+45+degree+dive+angle+technique+drill" },
  { id: "dv9", cat: "diving", name: "Reverse Cross-Step + Collapse", dur: 12, int: "Medium", desc: "Take two crossover steps in one direction, then collapse to save the other way. Coach serves the ball about half a second after you start moving. Trains you to change direction fast.", reps: "3 x 8 each direction", eq: ["Balls", "Cones", "GK Gloves"], cp: "Head stays still on the dive. Bottom hand first, top hand over. Quick feet to switch direction.", prog: "Faster pace; random direction changes; add a second save after", mistakes: "Slow crossover; head bobbing on the dive; reaching instead of actually diving", video: "https://www.youtube.com/results?search_query=goalkeeper+crossover+step+collapse+dive+drill" },
  { id: "rx1", cat: "reflexes", name: "Tennis Ball Drop Reactions", dur: 10, int: "Medium", desc: "Face away from the coach. Coach holds two tennis balls at shoulder height. When you hear the call, spin around. Coach drops one ball randomly. You have to catch it before it bounces twice.", reps: "4 x 10 drops each GK", eq: ["Tennis Balls"], cp: "Explode into that first step. Lock your eyes on the ball the instant you turn. Be light on your feet.", prog: "Drop from higher up; drop both one after the other; no verbal cue, just drop; add movement before the turn", mistakes: "Slow to react; eyes take too long to find the ball; feet feel stuck", video: "https://www.youtube.com/results?search_query=goalkeeper+tennis+ball+drop+reaction+drill" },
  { id: "rx2", cat: "reflexes", name: "Rebounder Rapid Fire", dur: 12, int: "High", desc: "Stand about 3 metres from a rebounder. Coach fires balls at it and they bounce back at random angles. Save six in a row, no rest between them.", reps: "5 x 6-ball sets", eq: ["Rebounder", "Balls", "GK Gloves"], cp: "Stay in the moment. Short memory after each ball. Quick hands, don't overthink it. Stay on your feet as much as you can.", prog: "Fire faster; change the angles; sprint between sets; mix in recovery saves", mistakes: "Staying on the ground; slow to recover; overthinking; losing focus", video: "https://www.youtube.com/results?search_query=goalkeeper+rebounder+rapid+fire+reaction+drill" },
  { id: "rx3", cat: "reflexes", name: "Reaction Ball Wall Drill", dur: 10, int: "Medium", desc: "Stand 2-3 metres from a wall. Throw a reaction ball against it. It bounces back at crazy angles. Try to catch it or knock it away.", reps: "3 x 3-minute sessions", eq: ["Reaction Ball"], cp: "Keep your hands ready the whole time. Try to read the angles. Move side to side quickly.", prog: "Throw harder; change your distance; only catches count; time yourself", mistakes: "Committing before the bounce; slow moving sideways; hands not ready", video: "https://www.youtube.com/results?search_query=goalkeeper+reaction+ball+wall+drill" },
  { id: "rx4", cat: "reflexes", name: "Three-Server Rapid Fire", dur: 15, int: "Max", desc: "Three coaches stand at different angles, each with a ball. You save one, then immediately turn to face the next server. Go around clockwise. No breaks.", reps: "4 x 9-ball sets", eq: ["Balls", "Cones", "GK Gloves"], cp: "Find the ball fast. Talk yourself through it. Stay hungry for the next one.", prog: "Add a fourth server; more power; less time between serves; put a mannequin in front as a screen", mistakes: "Slow to scan; not resetting your position; breaking down when tired", video: "https://www.youtube.com/results?search_query=goalkeeper+multi+server+rapid+fire+reaction+drill" },
  { id: "rx5", cat: "reflexes", name: "Deflection Save Drill", dur: 12, int: "High", desc: "Coach shoots from about 25 metres at a cone or mannequin placed 12 metres out. The ball deflects off it unpredictably. You have to read and react to the deflection.", reps: "4 x 8 deflections", eq: ["Balls", "Cones", "Mannequins", "GK Gloves"], cp: "Watch the coach's body, not the cone. Be ready to change direction mid-dive. Stay on your toes.", prog: "Harder shots; move the deflection point around; add more mannequins", mistakes: "Staring at the deflection point; committing before the deflection happens; flat-footed", video: "https://www.youtube.com/results?search_query=goalkeeper+deflection+save+reaction+drill" },
  { id: "rx6", cat: "reflexes", name: "Sound Cue Reaction Drill", dur: 10, int: "Medium", desc: "Close your eyes or face away. Coach makes a sound. On that signal, turn around and react to a ball that's already been placed or tossed. Trains how fast you go from hearing to seeing to moving.", reps: "3 x 12-15 reactions", eq: ["Balls", "GK Gloves"], cp: "How fast can you process the sound and find the ball? That switch from hearing to seeing has to be instant.", prog: "Different sounds; harder ball placements; less time to react; mix up the cues", mistakes: "Slow to process; eyes take too long to lock on; guessing instead of reacting", video: "https://www.youtube.com/results?search_query=goalkeeper+sound+cue+reaction+save+drill" },
  { id: "rx7", cat: "reflexes", name: "Close-Range Point-Blank Fire", dur: 10, int: "Max", desc: "Coach fires balls at a rebounder placed about 2 metres in front of you. The ball comes flying back at random angles. Six balls with about 3 seconds between each one.", reps: "5 x 6-ball sets", eq: ["Rebounder", "Balls", "GK Gloves"], cp: "Stay on your feet. Quick hands. Get up fast because the next one is always coming.", prog: "Less time between balls; more power; restrict which hand you can use", mistakes: "Going to ground when you don't need to; slow hands; losing concentration", video: "https://www.youtube.com/results?search_query=goalkeeper+point+blank+rebounder+reaction+drill" },
  { id: "rx8", cat: "reflexes", name: "Mirror Reaction Drill", dur: 8, int: "Medium", desc: "Face another keeper or the coach about 2-3 metres apart. They do random movements and you copy them instantly. Builds reaction time and body control.", reps: "3 x 2-3 min sessions", eq: [], cp: "React as fast as you can. Match their movements cleanly. Stay balanced.", prog: "Go faster; more random; add goalkeeper-specific moves; finish with a ball serve", mistakes: "Delayed reaction; sloppy copying; losing balance; guessing what's next", video: "https://www.youtube.com/results?search_query=goalkeeper+mirror+reaction+movement+drill" },
  { id: "rx9", cat: "reflexes", name: "Agility Ladder + Reaction Save", dur: 12, int: "High", desc: "Sprint through an agility ladder, and the second you come out, the coach fires a ball at you. You have to save it while your legs are still burning from the ladder.", reps: "3 x 10 sequences", eq: ["Agility Ladder", "Balls", "GK Gloves"], cp: "Quick feet through the ladder. Switch to save mode the instant you exit. Keep your technique together even when tired.", prog: "Harder ladder patterns; different patterns each time; tougher serves", mistakes: "Slow through the ladder; messy transition to the save; technique falls apart", video: "https://www.youtube.com/results?search_query=goalkeeper+agility+ladder+reaction+save+drill" },
  { id: "fw1", cat: "footwork", name: "10-Yard Lateral Shuffle", dur: 8, int: "Medium", desc: "Put two cones 10 yards apart. Shuffle to one, touch it, shuffle back, touch the other. Keep your feet apart the whole time. Small, quick steps.", reps: "3 sets x 8-10 reps", eq: ["Cones"], cp: "Small quick steps. Stay low. Keep your hands up and ready the whole time. Head stays still.", prog: "Wider distance; coach calls which way; add a save at the end; race against time", mistakes: "Feet crossing over; big strides; standing too tall; hands hanging down", video: "https://www.youtube.com/results?search_query=goalkeeper+lateral+shuffle+footwork+drill" },
  { id: "fw2", cat: "footwork", name: "T-Drill Footwork", dur: 10, int: "High", desc: "Set cones in a T shape. Sprint forward to the top, shuffle left, shuffle right back through the middle, then backpedal to the start. Covers every direction.", reps: "2 sets x 6-8 reps", eq: ["Cones"], cp: "Explode forward. Quick shuffles sideways. Controlled backpedal. Slow down properly at each cone.", prog: "Make it bigger; add a save at the end; race against someone; coach calls random directions", mistakes: "Not slowing down at the cones; crossing feet; standing too upright; losing balance", video: "https://www.youtube.com/results?search_query=goalkeeper+T+drill+footwork+agility" },
  { id: "fw3", cat: "footwork", name: "Agility Ladder In-and-Out", dur: 8, int: "Medium", desc: "Go through an agility ladder with in-and-out patterns. Both feet in each square, then one foot out to the side, repeat. Light, fast touches.", reps: "3-4 rounds of full ladder", eq: ["Agility Ladder"], cp: "Light on your feet. Keep a steady rhythm. Arms moving efficiently. Eyes up, not staring at the ladder.", prog: "Add sideways movement; go faster; coach calls a save after you finish; change directions", mistakes: "Heavy feet; staring down; losing the rhythm; inconsistent spacing", video: "https://www.youtube.com/results?search_query=goalkeeper+agility+ladder+in+out+footwork+drill" },
  { id: "fw4", cat: "footwork", name: "Box Shuffle Drill", dur: 10, int: "Medium", desc: "Four cones in an 8-by-8 yard square. Shuffle to each corner, touch the cone, come back to the middle. Keep going without stopping.", reps: "2-3 sets x 3-4 sequences", eq: ["Cones"], cp: "Small shuffle steps. Stop sharply at each cone. Adjust quickly. Keep your hands active.", prog: "Smaller box; go faster; coach calls which corner; add a save at each one; time it", mistakes: "Taking big strides; losing balance; overshooting the cones; hands hanging down", video: "https://www.youtube.com/results?search_query=goalkeeper+box+shuffle+footwork+drill" },
  { id: "fw5", cat: "footwork", name: "Basic Footwork Ladder Patterns", dur: 8, int: "Low", desc: "Simple agility ladder work. Two feet in each rung, lateral shuffle through, crossover steps. Just building your foundation.", reps: "4 passes each pattern", eq: ["Agility Ladder"], cp: "Stay light. Don't stare at the ladder. Get the rhythm right before you worry about speed.", prog: "Trickier patterns; go faster; combine with catching; add direction changes", mistakes: "Looking down; stomping; losing rhythm; bad posture", video: "https://www.youtube.com/results?search_query=goalkeeper+basic+footwork+ladder+patterns" },
  { id: "fw6", cat: "footwork", name: "Reactive Direction Changes", dur: 12, int: "High", desc: "Stand in the middle of a 20-by-20 yard box. Coach shouts a direction. Sprint 8-10 yards that way, stop sharp, and get back to the middle.", reps: "2 sets x 15-20 changes", eq: ["Cones"], cp: "Explosive first step. Stop under control. Plant your feet properly. Get back into ready position fast.", prog: "Faster calls; coach fakes you out; add a save at the endpoint; more distance", mistakes: "Slow first step; running past the cone; guessing; sloppy ready position on the way back", video: "https://www.youtube.com/results?search_query=goalkeeper+reactive+direction+change+footwork+drill" },
  { id: "fw7", cat: "footwork", name: "Lateral Bound Power Drill", dur: 10, int: "High", desc: "Cones 12 yards apart. Bound powerfully from side to side. Each time you land, set your ready position before you go again.", reps: "2 sets x 8-10 bounds", eq: ["Cones"], cp: "Push off explosively. Land on the balls of your feet. Stabilize right away. Hold your ready position.", prog: "Go wider; add a save when you land; coach points which way; add reactive element", mistakes: "Weak push-off; landing heavy; slow to set; inconsistent stance", video: "https://www.youtube.com/results?search_query=goalkeeper+lateral+bound+power+drill" },
  { id: "fw8", cat: "footwork", name: "Post-to-Post Movement", dur: 10, int: "Medium", desc: "Start on the right post. Coach says 'go' and you shuffle across to the left post. The second you get there and set, the coach shoots. You have to be completely still and ready when the shot comes.", reps: "4 x 8 reps", eq: ["Balls", "GK Gloves", "Cones"], cp: "Stay on your toes. Arrive set, not still sliding. Quick feet across the face of the goal.", prog: "Harder shots; random which post; add a second shot; less time to set", mistakes: "Crossing your feet; arriving off-balance; still moving when the shot comes", video: "https://www.youtube.com/results?search_query=goalkeeper+post+to+post+movement+drill" },
  { id: "fw9", cat: "footwork", name: "Pressure Advance & Recovery", dur: 12, int: "High", desc: "Start 6 yards from your line. Coach stands at 20 yards with a ball. On the signal, rush out aggressively. Coach either plays the ball or fakes. Either way, recover back to your line fast.", reps: "2 sets x 10-12 sequences", eq: ["Balls", "Cones"], cp: "Explode out. Stop under control. Get back just as fast as you went out. Be set before you reach your line.", prog: "More distance; coach adds a decision element; faster pace; add a save on the recovery", mistakes: "Slow coming out; sloppy recovery; losing balance; taking your eyes off the ball", video: "https://www.youtube.com/results?search_query=goalkeeper+advance+recovery+footwork+drill" },
  { id: "fw10", cat: "footwork", name: "Shuffle + Low Drive Save", dur: 12, int: "High", desc: "Cones 3 metres apart, 10 metres from goal. Shuffle between them. As soon as you touch a cone, the coach fires a low shot. Alternate sides.", reps: "4 x 8 shots each", eq: ["Balls", "Cones", "GK Gloves"], cp: "Don't dive if you can use your feet. Block with your body. Quick feet between the cones.", prog: "Wider cones; faster shots; add a second ball right after; less reaction time", mistakes: "Diving when you could just use your feet; slow shuffle; not being set when the shot comes", video: "https://www.youtube.com/results?search_query=goalkeeper+shuffle+low+drive+save+drill" },
  { id: "ps1", cat: "positioning", name: "Angle-Setting with Cones", dur: 12, int: "Medium", desc: "Place cones at five spots around the box to mark where you should stand for each angle. Coach calls a number, you sprint to the right cone and set. Then the coach shoots.", reps: "3 x 10 positions", eq: ["Cones", "Balls", "GK Gloves"], cp: "Cut the angle in half. Be set before the shot. Imagine a string from the ball through your body to the centre of the goal.", prog: "Faster shots; add a shuffle before; random order; coach fakes", mistakes: "Standing too far out; too deep; still moving when the shot comes", video: "https://www.youtube.com/results?search_query=goalkeeper+angle+positioning+cone+drill" },
  { id: "ps2", cat: "positioning", name: "Near-Post Blocking", dur: 12, int: "Medium", desc: "Coach stands wide at the edge of the box. You get tight to the near post, stay on your feet, and make yourself as big as possible. Coach drives it low. Save it and recover.", reps: "4 x 6 shots each side", eq: ["Balls", "Cones", "GK Gloves"], cp: "Shoulder near the post, step out one pace. Don't go down early. Stay big.", prog: "Faster shots; mix in far-post shots; change distances; add a rebound ball", mistakes: "Going to ground too early; standing on the goal line; making yourself small", video: "https://www.youtube.com/results?search_query=goalkeeper+near+post+blocking+positioning+drill" },
  { id: "ps3", cat: "positioning", name: "Multi-Angle Shooting Pressure", dur: 15, int: "High", desc: "Coach sets up 4-6 shooting spots around the box. Coach moves from spot to spot and shoots. You have to adjust your position for each angle as fast as possible.", reps: "2 sets x 10-12 shots", eq: ["Balls", "Cones", "GK Gloves"], cp: "Before the shot: feet set, knees soft, hands ready. Body between ball and goal. How far you come off your line depends on the angle.", prog: "Faster shots; less recovery time; add deflections; have to distribute after the save", mistakes: "Slow shifting sideways; overcommitting to one side; hands down; body not square to the ball", video: "https://www.youtube.com/results?search_query=goalkeeper+multi+angle+positioning+shot+stopping+drill" },
  { id: "ps4", cat: "positioning", name: "Sweeper-Keeper High Line", dur: 15, int: "High", desc: "You play a high line. Coach plays balls over the top at random. You decide: come out and sweep it up, or retreat back to your goal.", reps: "4 x 8 decisions", eq: ["Balls", "Cones"], cp: "If the ball is closer to the goal than to you, get back. Otherwise, go get it. Be loud about your decision. Sprint at an angle, not straight.", prog: "Vary your starting position; multiple balls in a row; add consequences for wrong calls", mistakes: "Standing too deep; standing too high; hesitating; making quiet decisions", video: "https://www.youtube.com/results?search_query=goalkeeper+sweeper+keeper+high+line+drill" },
  { id: "ps5", cat: "positioning", name: "Multi-Threat Coverage", dur: 15, int: "High", desc: "Coach sets cones to mark two or three threat positions. Coach passes between spots, and you adjust your position to cover whoever has the ball while keeping an eye on the others.", reps: "10 x 2-threat + 8 x 3-threat scenarios", eq: ["Balls", "Cones"], cp: "Work out which cone is the main danger. Position for that one but keep your eyes on the others. React to the ball, not the fake.", prog: "Faster passes between cones; change positions; add time pressure; move cones mid-drill", mistakes: "Covering the wrong spot; overcommitting; slow to react when the ball moves", video: "https://www.youtube.com/results?search_query=goalkeeper+positioning+multi+threat+coverage+drill" },
  { id: "ps6", cat: "positioning", name: "Rapid Recovery & Rebound Position", dur: 12, int: "High", desc: "Coach shoots and the ball is likely to rebound. Make the first save, then instantly get back into position to deal with the loose ball.", reps: "2 sets x 10-12 sequences", eq: ["Balls", "GK Gloves"], cp: "Solid first save. Recover immediately. Reset your ready position. Cover where the rebound might go. Eyes locked on the loose ball.", prog: "Harder shots; more realistic rebounds; less space to work with; coach plays a second ball", mistakes: "Slow to recover; bad position after the save; not covering the rebound area", video: "https://www.youtube.com/results?search_query=goalkeeper+rebound+recovery+positioning+drill" },
  { id: "ds1", cat: "distribution", name: "Drop-Kick Target Zones", dur: 12, int: "Medium", desc: "Set up target zones at 30, 40, and 50 metres. Drop-kick to each one, alternating distances. Targets are about 5 metres wide. Use both feet.", reps: "4 x 10 kicks", eq: ["Cones", "Balls"], cp: "Keep the drop consistent. Don't swing too hard. Lock your ankle, lean back slightly.", prog: "Smaller targets; coach moves the target; add a time limit", mistakes: "Over-swinging; dropping the ball differently each time; going for power instead of accuracy", video: "https://www.youtube.com/results?search_query=goalkeeper+drop+kick+target+accuracy+drill" },
  { id: "ds2", cat: "distribution", name: "Javelin/Overarm Throw", dur: 10, int: "Medium", desc: "Stand on the edge of the 6-yard box. Cone target at 25 metres. Turn side-on, arm back, drive off your back foot and throw it straight to the target.", reps: "3 x 8 each arm", eq: ["Balls", "Cones"], cp: "Elbow high, fingers behind the ball. Rotate your hips. Aim where the target would be moving to. Accuracy first, distance second.", prog: "Push the target further; coach moves the cone; add a time limit", mistakes: "Using just your arm; sloppy footwork; making it obvious where you're throwing", video: "https://www.youtube.com/results?search_query=goalkeeper+javelin+overarm+throw+drill" },
  { id: "ds3", cat: "distribution", name: "Goal Kick Accuracy Challenge", dur: 15, int: "Medium", desc: "Three target zones: short (15-20m), medium (35-40m), and long (50-55m). Take 6 kicks at each zone. Keep score of how many hit the target.", reps: "18 kicks (6 per zone)", eq: ["Cones", "Balls"], cp: "Plant foot placement is everything. Follow through fully. Practice with both feet equally. Each distance needs slightly different technique.", prog: "Add a time limit; push the distance; tighter targets; alternate feet", mistakes: "Inconsistent plant foot; lunging at the ball; bad timing; kicking too hard", video: "https://www.youtube.com/results?search_query=goalkeeper+goal+kick+accuracy+challenge+drill" },
  { id: "ds4", cat: "distribution", name: "Playing Through the Press", dur: 15, int: "High", desc: "Set cones at 15, 25, and 35 metres to represent passing targets. Coach runs at you to press. You have 3 seconds and max 3 touches to play it out to one of the targets.", reps: "4 x 8 scenarios", eq: ["Cones", "Balls"], cp: "First touch sets your direction. Second touch is the pass. Know where you're going before the ball arrives.", prog: "Less time; coach presses harder; feet only; targets further apart", mistakes: "Panicking; turning your back; not scanning before the ball comes", video: "https://www.youtube.com/results?search_query=goalkeeper+playing+out+from+back+under+pressure+drill" },
  { id: "ds5", cat: "distribution", name: "Underhand Roll Precision", dur: 8, int: "Low", desc: "Set cones at 5, 8, 12, and 15 yards. Roll the ball underhand to each target. Focus on getting the pace and direction spot on.", reps: "24 rolls (6 x 4 distances)", eq: ["Cones", "Balls"], cp: "Release it low. Keep it almost flat along the ground. Vary the pace. Roll it right to the target, not into empty space.", prog: "Coach presses while you roll; wider targets; cone moves between rolls; add a decision element", mistakes: "Too much pace; releasing at different heights; behind the target", video: "https://www.youtube.com/results?search_query=goalkeeper+underhand+roll+distribution+drill" },
  { id: "ds6", cat: "distribution", name: "Save + Counter-Launch", dur: 15, int: "High", desc: "Coach shoots at you. Make the save. Then immediately launch the ball to one of two cone targets set wide. You have 3 seconds from save to launch.", reps: "4 x 8 save-launches", eq: ["Balls", "Cones", "GK Gloves"], cp: "The save is only half the job. The quick launch is what matters. Get your eyes up before the ball is even in your hands. A throw is usually faster than a kick.", prog: "Less time; coach presses after the save; move the targets; harder shots to save", mistakes: "Slow transition; eyes on the ground; picking the wrong target", video: "https://www.youtube.com/results?search_query=goalkeeper+save+counter+attack+distribution+drill" },
  { id: "ds7", cat: "distribution", name: "Passing Circuit with Coach", dur: 15, int: "High", desc: "Set up a 20-by-20 grid with cones. Coach passes the ball to you from different angles. You receive and play it back quickly. Max 2 touches. Work on your first touch and passing with both feet.", reps: "3-4 rounds x 2-3 min", eq: ["Cones", "Balls"], cp: "Position yourself just outside the grid. Decide fast: play it back the way it came or switch it. Two touches max.", prog: "Smaller grid; coach presses you; feet only; faster tempo", mistakes: "Taking too long on the ball; overcomplicating it; bad positioning to receive", video: "https://www.youtube.com/results?search_query=goalkeeper+passing+circuit+footwork+distribution+drill" },
  { id: "ds8", cat: "distribution", name: "Both-Feet Kicking Mastery", dur: 12, int: "Medium", desc: "Alternate between right foot and left foot, hitting targets at 30, 40, and 50 yards. Four kicks per foot at each distance. Track how accurate you are.", reps: "24 kicks (alternate feet)", eq: ["Cones", "Balls"], cp: "Plant foot placement matters. Hit the right contact point. Full follow-through. Commit to your weak foot just as much as your strong one.", prog: "Add a time limit; coach moves targets; random distances; compete against yourself", mistakes: "Weak foot is lazy; poor plant foot; no follow-through", video: "https://www.youtube.com/results?search_query=goalkeeper+both+feet+kicking+weak+foot+drill" },
  { id: "ds9", cat: "distribution", name: "Back-Pass Build-Out", dur: 12, int: "Medium", desc: "Coach plays you a back-pass. You receive and pass to cone targets, building up in a chain. Coach presses you after each pass. If the press wins the ball within 4 passes, the drill resets.", reps: "4 x 8 build-outs", eq: ["Cones", "Balls"], cp: "Keep it simple. Start the chain with a clean pass. Communicate before the ball even gets to you.", prog: "Coach presses harder; less time; set specific passing patterns; longer distances", mistakes: "Holding the ball too long; forcing difficult passes; poor first touch", video: "https://www.youtube.com/results?search_query=goalkeeper+back+pass+build+out+drill" },
  { id: "ds10", cat: "distribution", name: "Half-Volley Width Switch", dur: 10, int: "Medium", desc: "Practice switching the ball to the far side with a half-volley. Target zone is 40+ metres away. Use both feet.", reps: "3 x 10 each foot", eq: ["Balls", "Cones"], cp: "Strike through the lower half of the ball. Lean back slightly for lift. Drop the ball in front of you, not to the side.", prog: "Coach presses while you set up; smaller target; move the cone; add a time limit", mistakes: "Slicing it; inconsistent drop; swinging too hard", video: "https://www.youtube.com/results?search_query=goalkeeper+half+volley+switch+play+drill" },
  { id: "cr1", cat: "crosses", name: "Three-Step Footwork to Cross", dur: 12, int: "Medium", desc: "Stand on the 6-yard line. Coach delivers a cross from wide. Use three steps to get there: side step, cross-step, then jump and claim it at the highest point.", reps: "5 x 8 crosses", eq: ["Balls", "Cones", "GK Gloves"], cp: "Attack the ball. Take off from your inside foot. Shout 'KEEPER' early and loud. Catch it at the highest point you can reach.", prog: "Add mannequins in the box; faster crosses; different delivery positions; vary the height", mistakes: "Waiting for the ball to come to you; messy footwork; catching behind your head", video: "https://www.youtube.com/results?search_query=goalkeeper+cross+claiming+footwork+three+step+drill" },
  { id: "cr2", cat: "crosses", name: "Catch vs Punch Decision", dur: 15, int: "High", desc: "Coach delivers crosses from different positions. Mannequins are in the box to simulate traffic. Decide whether to catch (shout 'keeper') or punch (shout 'away') based on how crowded it is.", reps: "4 x 10 crosses", eq: ["Balls", "Cones", "Mannequins", "GK Gloves"], cp: "Make your call early. If you're not sure, punch it hard and with direction. Decide before you jump, not while you're in the air.", prog: "More mannequins; faster crosses; mix heights and speeds; add deflection danger", mistakes: "Can't decide; going too far from goal; weak punch; not calling it", video: "https://www.youtube.com/results?search_query=goalkeeper+catch+vs+punch+decision+cross+drill" },
  { id: "cr3", cat: "crosses", name: "Corner Kick Organization", dur: 15, int: "Medium", desc: "Full corner practice. Set up cones to mark where your imaginary back line would stand. Coach delivers inswingers, outswingers, and short corners. You organize everything and deal with the ball.", reps: "3 x 8 scenarios", eq: ["Balls", "Cones", "GK Gloves"], cp: "Set your positions BEFORE the kick. Don't stand on your goal line. Call out what type of corner it is.", prog: "Game speed; add mannequins for traffic; mix corner types; score your organization", mistakes: "Organizing too late; standing on the goal line; not scanning before the kick", video: "https://www.youtube.com/results?search_query=goalkeeper+corner+kick+organization+positioning+drill" },
  { id: "cr4", cat: "crosses", name: "Crosses Under Fatigue", dur: 12, int: "High", desc: "Do 5 lateral shuffles of 10 metres each, then immediately claim a cross. The whole point is to handle crosses when your legs are tired.", reps: "4 x 8 crosses after shuffle", eq: ["Balls", "Cones", "GK Gloves"], cp: "Breathe. Reset yourself. Don't rush the footwork just because you're tired. Trust your technique.", prog: "More shuffles; less rest; add mannequins; faster crosses", mistakes: "Rushing when tired; technique falls apart; not calling for the ball", video: "https://www.youtube.com/results?search_query=goalkeeper+crosses+under+fatigue+conditioning+drill" },
  { id: "cr5", cat: "crosses", name: "Switching Crossing Zones", dur: 12, int: "High", desc: "Coach crosses from the right at 10 metres, then from the left at 20 metres, then from the right at 30 metres. You adjust your starting position for each one. Full-width range.", reps: "4 x 8 sequences", eq: ["Balls", "Cones", "GK Gloves"], cp: "Read the coach's body before the ball is hit. Start moving early. Make small adjustments as the ball is in the air.", prog: "Faster transitions; add mannequins; vary height; mix in punching", mistakes: "Slow to adjust; flat-footed; not reading the coach's body shape", video: "https://www.youtube.com/results?search_query=goalkeeper+switching+crossing+zones+adjustment+drill" },
  { id: "cr6", cat: "crosses", name: "Contested Cross Claiming", dur: 12, int: "High", desc: "Coach crosses from wide. A mannequin is in the 6-yard box. You have to claim or punch the ball even though you know contact with the mannequin is coming. Practice safe technique.", reps: "3 x 8 each GK", eq: ["Balls", "Cones", "Mannequins", "GK Gloves"], cp: "Catch it at the highest point. Bring your knee up for protection. Never hesitate. Full commitment.", prog: "Add more mannequins; faster crosses; vary delivery; keep score", mistakes: "Hesitating; catching too low; not protecting yourself; pulling out at the last second", video: "https://www.youtube.com/results?search_query=goalkeeper+contested+cross+claiming+drill" },
  { id: "cr7", cat: "crosses", name: "High-Pressure Corner Sequence", dur: 10, int: "Max", desc: "8 corners in 4 minutes. Alternating sides, different types. Claim or punch every single one. No breaks.", reps: "3 x 8-corner sequences", eq: ["Balls", "GK Gloves"], cp: "Trust your footwork. Call every ball. No ball should land unclaimed in your 6-yard box.", prog: "Add mannequins; keep score; go even faster; mix in free kicks", mistakes: "Mental tiredness; technique gets sloppy; not resetting between corners", video: "https://www.youtube.com/results?search_query=goalkeeper+high+pressure+corner+sequence+drill" },
  { id: "ov1", cat: "1v1", name: "1v1 Closing Down (Feet Set)", dur: 15, int: "High", desc: "Coach dribbles the ball from the 18-yard line towards goal. You come out, narrow the angle, and stay on your feet. No diving. Force the coach to go wide.", reps: "3 x 6 each GK", eq: ["Balls", "Cones", "GK Gloves"], cp: "Make yourself big. Stay on your feet. Wait and don't commit early. Read the touch on the ball, ignore body feints.", prog: "Coach goes faster; add a finish; come from different angles; coach can pass to a second ball", mistakes: "Committing too early; going to ground; getting beaten on the dribble; turning sideways", video: "https://www.youtube.com/results?search_query=goalkeeper+1v1+closing+down+stay+on+feet+drill" },
  { id: "ov2", cat: "1v1", name: "Smother Dive at Feet", dur: 12, int: "High", desc: "Coach runs at goal from 20 metres with the ball. You come out, wait for the right moment, then smother the ball at their feet. Safe, strong technique.", reps: "4 x 6 each GK", eq: ["Balls", "Cones", "GK Gloves"], cp: "Don't go too early. Get low and stay strong. Hands and body together. Lead with your fists, not your head.", prog: "Coach runs faster; angled runs; coach can chip it; live finishing attempts", mistakes: "Going too early; head first; diving sideways; getting chipped", video: "https://www.youtube.com/results?search_query=goalkeeper+smother+dive+at+feet+1v1+drill" },
  { id: "ov3", cat: "1v1", name: "Stay-on-Feet 1v1 Game", dur: 12, int: "High", desc: "Coach starts wide with the ball at 18 metres and comes at goal. Your job is to stay on your feet as long as possible and force the coach to make a decision. Only dive when the shot is actually hit.", reps: "4 x 8 each GK", eq: ["Balls", "Cones", "GK Gloves"], cp: "Don't sell yourself. Stay big. Only go to ground when the ball is struck. Make the coach decide, not you.", prog: "Add time pressure; coach starts from different spots; add a second ball; coach goes faster", mistakes: "Committing too early; on the ground before the shot; making yourself small", video: "https://www.youtube.com/results?search_query=goalkeeper+stay+on+feet+1v1+patience+drill" },
  { id: "ov4", cat: "1v1", name: "1v1 After Sweeping Recovery", dur: 12, int: "High", desc: "Sprint out to sweep a through-ball, then recover back to your line and immediately face a 1v1 as the coach comes at you with a second ball.", reps: "3 x 6 sequences", eq: ["Balls", "Cones", "GK Gloves"], cp: "Reset your breathing. Don't rush. Get your stance right. Stay calm after the effort.", prog: "Less recovery time; coach comes faster; add a third action; change the distances", mistakes: "Rushing the recovery; sloppy stance; carrying the tiredness; panicking", video: "https://www.youtube.com/results?search_query=goalkeeper+sweep+recovery+1v1+drill" },
  { id: "ov5", cat: "1v1", name: "1v1 From Different Angles", dur: 15, int: "High", desc: "Coach comes at you from six different angles: straight on, left 45, right 45, wide left, wide right, and after a pass from deep. Different angle means different position for you.", reps: "6 runs each GK", eq: ["Balls", "Cones", "GK Gloves"], cp: "Every angle needs a different starting position. Adjust before the coach gets close. Narrow the angle from the right spot.", prog: "Coach goes faster; different finishes; random order; make it a game", mistakes: "Same position for every angle; slow to adjust; not reading the angle", video: "https://www.youtube.com/results?search_query=goalkeeper+1v1+different+angles+positioning+drill" },
  { id: "ov6", cat: "1v1", name: "Controlled Advance Decision", dur: 12, int: "Medium", desc: "Coach receives the ball at 25 metres and dribbles towards goal. Another coach calls 'set' at the perfect moment to help you learn when to stop advancing. Over time, you learn the timing yourself.", reps: "4 x 8 each GK", eq: ["Balls", "Cones", "GK Gloves"], cp: "Come out fast, set early. Be a big obstacle. Read the touch on the ball.", prog: "Remove the coach's call; coach goes faster; add fakes; add a lob threat", mistakes: "Setting too late; setting too early; coming out at the wrong speed", video: "https://www.youtube.com/results?search_query=goalkeeper+1v1+advance+timing+decision+drill" },
  { id: "sp1", cat: "set-pieces", name: "Penalty Routine Practice", dur: 15, int: "High", desc: "5 penalties from the coach or another keeper. Build a pre-kick routine: stance, focus, breathe. React to the shot, don't guess. Keep notes on where each one goes.", reps: "5 per GK", eq: ["Balls", "GK Gloves"], cp: "Stay on the line. Explode to the corner. Watch the hips. Having a routine takes the fear away.", prog: "Add crowd noise; delayed run-ups; full shootout simulation; make it competitive", mistakes: "Moving too early; changing your routine each time; just guessing", video: "https://www.youtube.com/results?search_query=goalkeeper+penalty+save+routine+practice+drill" },
  { id: "sp2", cat: "set-pieces", name: "Free Kick Wall + Position", dur: 12, int: "Medium", desc: "Free kicks from 20, 22, and 25 metres. Line up mannequins as a wall to cover the near post. You position yourself for the far post. Save what comes over or around the wall.", reps: "4 x 8 free kicks", eq: ["Balls", "Cones", "Mannequins", "GK Gloves"], cp: "Check the wall is right before you look at the coach. Cover the gap between the wall and the post. Position yourself for an over-the-wall shot.", prog: "Vary distances; add dummy runs with cones; add rebound saves", mistakes: "Not checking the wall; standing too central; guessing", video: "https://www.youtube.com/results?search_query=goalkeeper+free+kick+wall+positioning+drill" },
  { id: "sp3", cat: "set-pieces", name: "Post-Corner Transition Save", dur: 12, int: "High", desc: "Coach delivers a corner. Claim it or punch it. Then within 2 seconds, a second ball is shot from the edge of the box. You have to reset and save it.", reps: "3 x 8 sequences", eq: ["Balls", "Cones", "GK Gloves"], cp: "Land with your eyes on the play. Scan immediately. Get your feet moving to reset.", prog: "Less time between balls; multiple follow-up shots; tougher serves; add mannequins", mistakes: "Landing off-balance; not scanning; slow to get back into position", video: "https://www.youtube.com/results?search_query=goalkeeper+corner+kick+transition+second+ball+drill" },
  { id: "sp4", cat: "set-pieces", name: "Full Penalty Shootout Sim", dur: 15, int: "Max", desc: "5 penalties against other keepers or the coach. Keep a scoreboard. First keeper to save 2 wins. Make it feel real.", reps: "5 per GK in shootout", eq: ["Balls", "GK Gloves"], cp: "Embrace the pressure. Do your routine exactly the same every single time.", prog: "Add crowd noise; different shooting styles; change the order; add consequences for losing", mistakes: "Abandoning your routine; guessing out of fear; losing focus between kicks", video: "https://www.youtube.com/results?search_query=goalkeeper+penalty+shootout+simulation+drill" },
  { id: "sp5", cat: "set-pieces", name: "Set-Piece Mental Walk-Through", dur: 10, int: "Low", desc: "No ball needed. Coach calls out scenarios ('corner from the left, inswinger') and you physically walk through where you'd stand, what you'd call, and where you'd move. Build the habits without the chaos.", reps: "3 x 6 scenarios", eq: [], cp: "Visualize it clearly. Walk through it slowly and accurately. You're building the mental pathway so it's automatic in a game.", prog: "More complex scenarios; add verbal responses; do it faster", mistakes: "Rushing through it; not committing mentally; treating it like it doesn't matter", video: "https://www.youtube.com/results?search_query=goalkeeper+set+piece+mental+visualization+walkthrough" },
  { id: "cm1", cat: "communication", name: "Verbal Box Communication", dur: 12, int: "Medium", desc: "Coach delivers crosses. Before each one, you practise calling out where the danger is, who should cover what, and where the ball is going. Coach scores you on how early, specific, and loud your calls are.", reps: "3 x 10 crosses", eq: ["Balls", "Cones"], cp: "Call before the cross, not during. Be specific. Be loud. Use names if you're working with other keepers.", prog: "Increase tempo; score the quality of calls; add more complexity to the scenarios", mistakes: "Late calls; vague instructions; too quiet", video: "https://www.youtube.com/results?search_query=goalkeeper+communication+box+command+drill" },
  { id: "cm2", cat: "communication", name: "Back Line Direction (No Ball)", dur: 10, int: "Low", desc: "Set up cones as an imaginary back line. Coach walks through 6 different scenarios. You call every instruction: step up, drop, shift left, shift right. No ball, just your voice and positioning.", reps: "3 x 6 scenarios", eq: ["Cones"], cp: "Your voice should never stop. Be specific: 'step up,' 'drop,' 'shift left.' Don't wait for something to go wrong.", prog: "Go faster; add a ball; coach tests you with surprise scenarios; score your calls", mistakes: "Waiting for the problem before speaking; being quiet; generic calls", video: "https://www.youtube.com/results?search_query=goalkeeper+back+line+communication+organizing+drill" },
  { id: "cm3", cat: "communication", name: "Communication Under Fatigue", dur: 10, int: "High", desc: "Do a 2-minute shuttle run. Then immediately organize cones as a back line while the coach walks through scenarios for 2 minutes. Coach checks if your voice stays loud and clear when you're gassed.", reps: "4 x 2-min sets", eq: ["Cones", "Balls"], cp: "Real leaders communicate when it's hard. Keep your volume and clarity up even when you can barely breathe.", prog: "More running; harder scenarios; score your communication quality", mistakes: "Going quiet; losing clarity; stopping communication altogether", video: "https://www.youtube.com/results?search_query=goalkeeper+communication+under+fatigue+drill" },
  { id: "cm4", cat: "communication", name: "GK-Led Organization Drill", dur: 15, int: "Medium", desc: "Set up cones as your imaginary back line. You give all the commands: step up, drop, shift, set. No coach help. You're in charge. Coach just observes and gives feedback after.", reps: "10 min per GK", eq: ["Cones"], cp: "You own the back line. Your voice is the first and last thing they hear. Be confident and decisive.", prog: "Coach adds surprise scenarios; go at game speed; add a ball; score your leadership", mistakes: "Hesitant; only reacting instead of leading; losing authority", video: "https://www.youtube.com/results?search_query=goalkeeper+leadership+organizing+back+line+drill" },
  { id: "cm5", cat: "communication", name: "Switchplay Recovery Calls", dur: 10, int: "Medium", desc: "Coach passes the ball quickly from one side to the other. You practise calling 'switch!' early and adjusting your position before the ball arrives on the other side.", reps: "4 x 8 scenarios", eq: ["Balls", "Cones"], cp: "See the switch before it happens. Call it before the ball gets there. Reposition while the ball is moving.", prog: "Faster switches; more options; add a shot after the switch; score your timing", mistakes: "Calling too late; not repositioning; being quiet", video: "https://www.youtube.com/results?search_query=goalkeeper+switchplay+communication+repositioning+drill" },
  { id: "ph1", cat: "physical", name: "GK Plyometric Circuit", dur: 15, int: "High", desc: "Circuit of four exercises: box jumps x8, lateral bounds x8 each side, squat jumps with clap x8, explosive push-ups x8. Take 90 seconds rest between rounds.", reps: "4 circuits", eq: ["Hurdles", "Cones"], cp: "Maximum effort on every single rep. This is about explosive power. Quality over quantity.", prog: "Add more exercises; less rest; more reps; add a save after each round", mistakes: "Sloppy form; not going hard enough; rushing through it", video: "https://www.youtube.com/results?search_query=goalkeeper+plyometric+circuit+explosive+power+drill" },
  { id: "ph2", cat: "physical", name: "Box Jump + Dive Save", dur: 12, int: "High", desc: "Jump onto a 40cm box and back off. The moment you land, coach fires a low ball to one side. Dive and save it straight from the landing.", reps: "4 x 6 each side", eq: ["Hurdles", "Balls", "GK Gloves"], cp: "Land soft, absorb the impact, then explode towards the ball. No freezing. Generate your power from the landing.", prog: "Higher box; more jumps before the save; harder shots; vary the direction", mistakes: "Freezing on the landing; bad mechanics; slow transition from jump to dive", video: "https://www.youtube.com/results?search_query=goalkeeper+box+jump+dive+save+plyometric+drill" },
  { id: "ph3", cat: "physical", name: "Sprint Recovery Sequences", dur: 12, int: "High", desc: "Sprint 20 metres out, walk back, and then face a shot from the coach immediately. 8 reps. Simulates sweeping up and then dealing with a follow-up shot.", reps: "4 x 8 sprint-saves", eq: ["Balls", "Cones", "GK Gloves"], cp: "Control your breathing in the last 3 steps. Arrive balanced and set. Keep your save quality high even when you're tired.", prog: "Longer sprints; less walking time; add a second shot; harder serves", mistakes: "Arriving off-balance; bad breathing; technique falling apart", video: "https://www.youtube.com/results?search_query=goalkeeper+sprint+recovery+shot+stopping+conditioning+drill" },
  { id: "ph4", cat: "physical", name: "Lateral Sprint + Collapse Dive", dur: 12, int: "High", desc: "Sprint to a cone 10 metres away, touch it, sprint back, and collapse to save a ball on the far side. Alternate directions.", reps: "4 x 8 each direction", eq: ["Balls", "Cones", "GK Gloves"], cp: "Full sprint every time. Your save quality still matters even when it's a conditioning drill. This is match simulation.", prog: "Longer sprints; add a second save; harder shots; add obstacles", mistakes: "Jogging instead of sprinting; lazy saves; not getting set before the shot", video: "https://www.youtube.com/results?search_query=goalkeeper+lateral+sprint+collapse+dive+conditioning+drill" },
  { id: "ph5", cat: "physical", name: "Plyometric Jump + Cross Claim", dur: 10, int: "High", desc: "Do two big vertical jumps. Right after landing, the coach delivers a cross. Claim it with your heart rate already up.", reps: "3 x 8 sequences", eq: ["Balls", "GK Gloves"], cp: "Control your breathing before the jump. Trust your technique even when your heart is pounding.", prog: "More jumps; less recovery; add mannequins; vary the cross", mistakes: "Bad timing on the claim; rushing; not breathing properly", video: "https://www.youtube.com/results?search_query=goalkeeper+plyometric+jump+cross+claim+drill" },
  { id: "mn1", cat: "mental", name: "Goal Visualization Exercise", dur: 15, int: "Low", desc: "15 minutes of guided visualization. Coach talks you through your best save, your best distribution, commanding a corner. Close your eyes and feel everything: the noise, the ball, the ground.", reps: "15 minutes", eq: [], cp: "Your brain can't tell the difference between a vivid mental image and reality. Make it as real as possible.", prog: "More specific scenarios; match-day situations; do it individually; build it into pre-match routine", mistakes: "Not committing to it; rushing; losing focus", video: "https://www.youtube.com/results?search_query=goalkeeper+visualization+mental+training+exercise" },
  { id: "mn2", cat: "mental", name: "Noise + Distraction Saves", dur: 12, int: "High", desc: "While you're getting ready for a shot, the coach makes noise, waves arms, shouts your name. You block it all out and make the save. Simulates a hostile crowd.", reps: "4 x 10 shots under distraction", eq: ["Balls", "GK Gloves"], cp: "Find your focal point. Everything else is just noise. The only thing that matters is the ball.", prog: "More distraction; louder; different types; score your focus", mistakes: "Losing focus; getting frustrated; technique suffering because of the noise", video: "https://www.youtube.com/results?search_query=goalkeeper+distraction+focus+pressure+save+drill" },
  { id: "mn3", cat: "mental", name: "Game State: Winning by 1", dur: 12, int: "Medium", desc: "Simulate being ahead by 1 goal late in the game. Practise when to hold the ball, when to slow things down within the rules. Coach creates scenarios to test your decision-making.", reps: "2 x 10-min scenarios", eq: ["Balls", "Cones"], cp: "Be smart, not cynical. Stay composed. Project calm leadership to everyone around you.", prog: "More pressure; different game states; add a referee role", mistakes: "Being too obvious about it; rushing; losing your composure", video: "https://www.youtube.com/results?search_query=goalkeeper+game+management+winning+mental+drill" },
  { id: "mn4", cat: "mental", name: "Game State: Losing by 1", dur: 12, int: "Medium", desc: "Simulate being behind in the last 10 minutes. Practise taking calculated risks: launching the ball faster, pushing up higher, communicating urgency to your team.", reps: "2 x 10-min scenarios", eq: ["Balls", "Cones"], cp: "Take the right risk at the right moment. Urgency without panic. Stay in control.", prog: "Different game states; multiple scenarios; combine with a shootout", mistakes: "Being reckless; panicking; losing composure; abandoning your position", video: "https://www.youtube.com/results?search_query=goalkeeper+game+management+losing+urgency+mental+drill" },
  { id: "mn5", cat: "mental", name: "Ice-Water Mentality Sim", dur: 8, int: "High", desc: "Before a routine save, the coach says something like 'This is the playoff shootout. If you concede, it's over.' Then you do your normal routine anyway. The point is to disconnect pressure from performance.", reps: "3 high-pressure penalties weekly", eq: ["Balls", "GK Gloves"], cp: "Pressure is a privilege. Your routine stays identical no matter what.", prog: "Ramp up the pressure; have other keepers watch; add consequences; combine with visualization", mistakes: "Changing your technique because of the pressure; overthinking; abandoning your routine", video: "https://www.youtube.com/results?search_query=goalkeeper+pressure+mentality+penalty+training+drill" },
  { id: "mn6", cat: "mental", name: "Season Stats Personal Review", dur: 15, int: "Low", desc: "Sit down with the coach and go through your numbers: save percentage, distribution accuracy, how you've done on crosses, penalty data. Talk about what they mean and what to work on.", reps: "15 min each GK", eq: [], cp: "Numbers tell one story, but what's behind them matters more. This is about building self-awareness.", prog: "Track weekly; compare trends over time; set targets; compare with past performance", mistakes: "Ignoring the data; getting defensive about weaknesses; not setting actual goals", video: "https://www.youtube.com/results?search_query=goalkeeper+performance+analysis+review+session" },
  { id: "rc1", cat: "recovery", name: "Dynamic Mobility + Activation", dur: 10, int: "Low", desc: "Hip circles, upper back rotations, hamstring sweeps, ankle rolls. Lead yourself through it. This is about getting blood flowing, not getting fit.", reps: "10 minutes", eq: [], cp: "About 40% effort. Breathe deeply. Build a routine you do the same way every time.", prog: "Add goalkeeper-specific movements; focus on quality; do it with a partner", mistakes: "Going too hard; just sitting there passively; rushing; skipping body parts", video: "https://www.youtube.com/results?search_query=goalkeeper+dynamic+mobility+activation+warmup" },
  { id: "rc2", cat: "recovery", name: "Light Technical Touches", dur: 15, int: "Low", desc: "Stand about 8 metres from the coach or another keeper. Roll, catch, and throw the ball back and forth. Clean hands, good shape, zero pressure. This is recovery, not training.", reps: "15 minutes", eq: ["Balls", "GK Gloves"], cp: "Perfect technique at slow speed. You're reinforcing good habits. Keep it relaxed.", prog: "Mix up the heights; add gentle movement; slightly pick up the pace; add footwork patterns", mistakes: "Going too hard; turning it into a competition; sloppy technique; rushing", video: "https://www.youtube.com/results?search_query=goalkeeper+light+technical+handling+recovery+drill" },
  { id: "rc3", cat: "recovery", name: "Match Debrief Discussion", dur: 15, int: "Low", desc: "Coach leads a conversation. What went well? What didn't? Name one thing you're proud of and one thing you'd change. Honest self-assessment.", reps: "15 minutes", eq: [], cp: "No blame. Only learning. Build a culture where being honest is normal.", prog: "Add video review; get feedback from other keepers; set goals; write it down", mistakes: "Blaming others; only focusing on negatives; being too vague", video: "https://www.youtube.com/results?search_query=goalkeeper+match+debrief+performance+review" },
  { id: "rc4", cat: "recovery", name: "Ball Mastery Free Play", dur: 15, int: "Low", desc: "Just play with the ball. Juggle, roll it, toss it around. No instructions. The point is to enjoy handling the ball without any pressure.", reps: "15 minutes", eq: ["Balls"], cp: "Have fun with it. No pressure. No scores. Just you and the ball.", prog: "Try tricks; friendly challenges with another keeper; use different types of balls", mistakes: "Taking it too seriously; not participating; losing interest", video: "https://www.youtube.com/results?search_query=goalkeeper+ball+mastery+free+play+fun+drill" },
  { id: "rc5", cat: "recovery", name: "Pre-Match Warm-Up Routine", dur: 25, int: "Medium", desc: "Full match-day warm-up. Jog, mobility, ladder, catching, low shots, high shots, crosses. Do it the same way every single time so it becomes automatic.", reps: "25 minutes", eq: ["Balls", "Agility Ladder", "Cones", "GK Gloves"], cp: "The ritual builds readiness. Same routine every week. It should feel automatic.", prog: "Fine-tune based on how you feel; add match-specific elements; personalise it over time", mistakes: "Changing the routine; skipping parts; not going hard enough", video: "https://www.youtube.com/results?search_query=goalkeeper+pre+match+warmup+routine" },
  { id: "rc6", cat: "recovery", name: "Post-Session Cool Down", dur: 10, int: "Low", desc: "Light jog and static stretching. Lead yourself through it. Build the habit of taking care of your body after every session.", reps: "10 minutes", eq: [], cp: "Professional keepers cool down. Every time. No exceptions.", prog: "Add foam rolling; breathing exercises; short meditation", mistakes: "Skipping it; rushing through it; waiting for someone to tell you what to do", video: "https://www.youtube.com/results?search_query=goalkeeper+post+session+cool+down+stretching+routine" },
];

